import sdk from '@lev-os/sdk'

const session = await sdk.agent.session({
  task: 'Run an architecture interview for the tmux control plane',
  flow: 'arch-interview',
  adapter: 'claude-agent-sdk',
  model: 'claude-opus-4-7',
  substrate: 'tmux://arch-interview',
  profile: 'sdlc.flowmind.exec',
  variables: { depth: 'deep' },
  contextPressureThreshold: 0.5,
})

for await (const event of session.stream()) {
  // text, tool, usage, receipt, context pressure, checkpoint
}

await session.attach()
await session.cancel('user')
const receipt = await session.wait()

const flow = sdk.flow.define('arch-interview', (f) => {
  const interviewer = f.agent('interviewer', {
    op: 'lev.exec',
    adapter: 'claude-agent-sdk',
    args: { role: 'interviewer' },
  })

  const architect = f.agent('architect', {
    op: 'lev.exec',
    adapter: 'claude-agent-sdk',
    args: { role: 'architect' },
  })

  f.edge(interviewer, architect, { gate: 'ambiguity <= 0.2' })
})

const suite = sdk.eval.suite('arch-interview-quality', (t) => {
  t.constraint('asks-one-question-at-a-time', ({ transcript }) => {
    expect(transcript.openQuestionsPerTurn).toBeLessThanOrEqual(1)
  })

  t.finalBoss('no-hidden-fallbacks', {
    flow: 'sdk-runtime-final-boss',
    gates: ['no_silent_noops', 'receipts_present', 'policy_gated_actions'],
  })
})

await sdk.eval.run(suite, { session, failClosed: true })
